var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"왕이시여, 잠시 연주를 멈추어도 될지요.","JPN":"王様、しばらく演奏を中断してもよろしいでしょうか。","ENG":"My lord, may I request an intermission?","TWN":"我的王，可以暫時停止演奏嗎。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"이유를 들어 봐도 될까요, 네퀴티아?","JPN":"理由を聞いてもいいですか？　ネキティア。","ENG":"May we hear why, Nequitia?","TWN":"能說出你的理由嗎，莉奎蒂亞？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"이대로는 왕의 뜻에 걸맞은 음률을 자아내기에 부족함이 있군요.","JPN":"今の状態で王様の意志に相応しい音律を奏でるのは少々無理があります。","ENG":"I fear that the song is unfitting of your request, my lord.","TWN":"照這樣下去，還不足以發出符合王旨意的音律。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"정비할 시간을 허락해 주신다면 최선을 다해 조율하도록 하겠습니다.","JPN":"整備する時間をお許しいただけるのなら、一生懸命調律いたします。","ENG":"With your permission, I will do my best to retune my instruments.","TWN":"如果你同意給我調整的時間，我會盡最大努力去協調。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"아하, 그래서군요. 어쩐지 반응이 너무 늦다 했어요.","JPN":"ああ、だからなのですね。反応が遅すぎると思いました。","ENG":"Oh, that's why. No wonder the response was late.","TWN":"哈，原來是因為這樣。怪不得反應太慢了。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"그런 문제라면 얼마든지 시간을 할애하셔도 괜찮답니다. 의식은 거의 완성되어 가니까요.","JPN":"そのような問題でしたら、いくら時間を割いても構いません。儀式はほぼ完成されている状態ですから。","ENG":"If that is the case, we will give you as much time as you require. The ritual is nearly complete.","TWN":"如果只是這種問題，那你花多少時間都沒關係。因為儀式就快完成了。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"채비는 어디까지나 레지나 님께서 돌아오실 때까지만 마칠 수 있으면 돼요.","JPN":"レジーナ様がお戻りになる時までに準備ができていれば問題ありません。","ENG":"Nonetheless, you must finish before Miss Regina returns.","TWN":"只要在蕾佳娜回來之前，做好一切準備就可以。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"허락해 주셔서 감사합니다. 그럼 잠시.","JPN":"お許しいただき、ありがとうございます。それでは。","ENG":"Thank you, my lord. I will be prompt.","TWN":"謝謝你的允許，那我先暫停一下。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"루나, 이리 오세요.","JPN":"ルナ、こちらにいらっしゃい。","ENG":"Luna, please come over here.","TWN":"露娜，過來。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"지, 지휘자님…….","JPN":"ま、マエストロ……","ENG":"C-Chief Conductor...?","TWN":"指…指揮家……"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"그새 인간과 정이 드셨나요?","JPN":"もう人間と馴染んでしまったのですか？","ENG":"Have you already developed feelings for humans these past few days?","TWN":"你這麼快就和人類產生感情了嗎？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"셰나와 카르멘에게 들키지 않으면서 음정을 어긋나게 하다니……","JPN":"シェナとカルメンに悟られずに、ずれた音程を出すとは……","ENG":"You were playing out of tune without Shena or Carmen noticing...","TWN":"你居然背著世娜和卡門偷偷吹錯旋律……"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"시기를 늦추려고 애쓰는 꼴이 참으로 갸륵하군요.","JPN":"どうにか時期を遅らせようとしている姿が、とても健気ですね。","ENG":"It's pathetic seeing you struggle to delay the ritual.","TWN":"你努力拖延時間的樣子，真是讓人敬佩。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"대답해 보세요. 제가 눈이 어두워 모르리라고 생각했나요.","JPN":"答えなさい。私の目が見えないから、知らないとでも思ったのですか？","ENG":"Answer me. Or did you think I wouldn't notice because I am blind?","TWN":"回答我。你以為我眼睛瞎了，就不能察覺嗎。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"아, 아니요! 절대 그렇지 않아요!","JPN":"い、いいえ！　絶対そんなことは！","ENG":"N-no! I would never!","TWN":"不…不是的！絕對不是那樣的！"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"그렇다면 당신이 무엇인지 말씀해 보세요.","JPN":"でしたら、あなたが何者か言ってごらんなさい。","ENG":"Then will you remind me who you are again?","TWN":"那你說說看，自己到底是誰。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"저, 저는 엘리시움 필하모닉의 나팔수로서……","JPN":"あ、アタシはエリシウムフィルハーモニーのトランぺット奏者で……","ENG":"I'm... I'm the trumpeter of Elysium Philharmonic...","TWN":"我、我是愛樂組織的小號手……"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"최고 지휘자님의 악기…… 입니다…….","JPN":"マエストロの楽器……です……","ENG":"and the Chief Conductor's... instrument...","TWN":"首席指揮家的樂器……"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"훌륭해요, 루나.","JPN":"素晴らしいです、ルナ。","ENG":"Excellent, Luna.","TWN":"很好，露娜。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"위치로 돌아가세요. 다음은 없습니다.","JPN":"位置に戻りなさい。次はありません。","ENG":"Please go back to your seat. This will be your last chance.","TWN":"回到你的位置上，下不為例。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"하아……. 머저리 같으니라고.","JPN":"はあ……バカじゃないの？","ENG":"*Sigh...* What an idiot she is.","TWN":"哈啊……你這個笨蛋。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"지휘자님 심기도 불편한데 가지가지 하는구나, 너.","JPN":"マエストロもご機嫌斜めなのに、あなたやらかしてくれるわね。","ENG":"Conductor's already in a bad mood, why are you fueling her fire?","TWN":"指揮家心情本來就不好，你還敢惹她。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"목에 바람 구멍 뚫릴 건 무섭고 백치가 되는 건 안 무섭나 봐?","JPN":"首に風穴開けられるのは怖くても、バカになるのは怖くないのかしら。","ENG":"You're scared of getting punctured in the throat, but not about making a fool out of yourself?","TWN":"你害怕在脖子上開幾個洞，就不怕成為白癡嗎？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"으으……. 나, 나도 최선을 다하고 있는걸……","JPN":"うう……あ、アタシも頑張ってるんだ……","ENG":"Ngh... I-I'm doing my best...","TWN":"嗚嗚……我…我也盡力了……"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L35_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"어머나, 최선을 다하는 게 그 정도라면 그냥 소멸시키는 편이 낫지 않아?","JPN":"あら、頑張ってそれくらいなら、いっそ消滅させた方がよくない？","ENG":"Oh my, if that's your best, wouldn't it be better to just perish?","TWN":"天啊，如果你盡力了，才僅僅做到這種水準的話，應該被直接消滅吧？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L36_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"대신에 중사님을 들이면 어때? 지휘자님도 마음에 들어하시던걸.","JPN":"代わりに軍曹さんを雇うのはどう？　マエストロも気に入ってるみたいだし。","ENG":"How about we bring in Sergeant instead? Chief Conductor seems to like her a lot.","TWN":"讓中士代替她怎麼樣？指揮家肯定也會滿意。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L38_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"그로니아에서 오래 지내더니 주제를 모르네. 멋대로 편제에 관여하지 마.","JPN":"グロニアにいた時間が長いからって、調子に乗って。勝手に編制に関わらないでちょうだい。","ENG":"Maybe all that time in Gronia has messed up your brain. Don't you dare tamper with our composition.","TWN":"看來你是在格羅尼亞生活太久，所以連規矩都忘了。不要隨便干涉人員編制問題。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"그 꼬마가 와 봤자 내 줄 자리는 객석 청소밖에 없어.","JPN":"あのガキが来たって、せいぜいやらせるのは客席の掃除くらいよ。","ENG":"All that little brat can do here is clean the auditorium.","TWN":"就算那個小鬼來了，能給她安排的工作，也就只有打掃觀眾席而已。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"백 년쯤 노력하면 캐스터네츠 말단쯤은 될까?","JPN":"百年くらい努力すれば、カスタネットの末席くらいにはなれるかしらね？","ENG":"Maybe after about 100 years, she can be a standby of castanets player?","TWN":"再努力一百年吧，或許能混到樂團響板的位置吧？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"흐응……. 그래?","JPN":"ふーん……そう？","ENG":"Hmm... Is that so?","TWN":"嗯……是嗎？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L44_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"하지만 어쩔 수 없는걸. 지휘자님이 예전 같지 않으시다는 건 너도 알잖니.","JPN":"でも仕方ないわよ。マエストロが前とは違うということは君も知っているでしょう？","ENG":"What else are we able to do? You know that Chief Conductor isn't the same person she used to be.","TWN":"不過沒辦法。你也知道，指揮家跟以前不一樣了。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L45_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"원래 같았으면 방금 전에 루나는 네 발로 기어다니고 있었어.","JPN":"昔だったら、さっきのでルナは四つ足で這うことになっていたはずよ。","ENG":"Back in her prime, she would've made Luna crawl on all fours.","TWN":"要是換做以前，剛才露娜就得用四隻腳爬著回來。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L46_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"그, 그런 말 하지 마……!","JPN":"そ、そんなこと言わないで……！","ENG":"D-don't say that...!","TWN":"別…別這麼說……！"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"아니, 하지 말아 주세요……","JPN":"いや、言わないでください……","ENG":"I mean, please don't...","TWN":"我是說，請不要這麼說！"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"충언이 필요한 시기 아닐까, 셰나 님?","JPN":"忠告が必要な時期ではないかしら。ね、シェナさん？","ENG":"Don't you think it's time to set things straight, Shena?","TWN":"應該是需要忠告的時候吧，世娜？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"전원. 정숙하세요.","JPN":"全員。静粛に。","ENG":"Silence, everyone.","TWN":"全員保持安靜。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L4_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"왕이시여. 준비는 마쳤사오나……","JPN":"王様。準備は終わりましたが……","ENG":"My lord. Everything is now in order...","TWN":"我的王，準備好了嗎……"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"멀리서부터 익숙한 기척이 다가오고 있군요.","JPN":"遠くから覚えのある気配が近づいてきています。","ENG":"However, I feel a familiar presence approaching.","TWN":"從遠處傳來了熟悉的動靜呢。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"아, 죄송해요. 레지나 님을 뵐 생각에 까맣게 몰랐네요.","JPN":"あ、すみません。レジーナ様にお会いすることでいっぱいで、完全に忘れていました。","ENG":"Oh, sorry. We were so excited to reunite with Miss Regina that we didn't notice.","TWN":"啊，抱歉，我滿腦子都是要見到蕾佳娜的事。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"저희와 인연이 있는 만큼, 폐가 되지 않는다면 응대하도록 하겠습니다.","JPN":"私たちとの縁もありますから、ご迷惑でなければ接待いたしますが。","ENG":"We have met this before, so if it's not a nuisance, we would like to take care of it.","TWN":"既然他和我們有些淵源，如果不麻煩的話，可以去迎接一下。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"어떠신지요?","JPN":"いかがでしょうか。","ENG":"Will that be okay?","TWN":"你覺得怎麼樣？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"흐음…….","JPN":"ふむ……","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"좋아요. 생물학부장님도 자리를 비우셨으니까요.","JPN":"いいですよ。生物学部長も留守ですからね。","ENG":"Very well. The Dean of Biology is currently absent as well.","TWN":"好，正好生物學院院長也不在。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"그 대신, 한 분은 남아 주셔야겠어요. 레지나 님을 위해 의식은 진행되어야 하잖아요?","JPN":"その代わり、一人は残っていただきます。レジーナ様のために、儀式は続けられるべきでしょう？","ENG":"But before that, I would like one of you to stay here. We must continue the ritual for Miss Regina, do we not?","TWN":"不過，要留下一位。還得為蕾佳娜進行儀式不是嗎？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"그 일이라면 적합한 단원이 있지요.","JPN":"その仕事でしたら、相応しい団員がいます。","ENG":"For that, I have the perfect member in mind.","TWN":"如果是這件事，那正好有個合適的團員。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"루나, 왕께 인사드리세요.","JPN":"ルナ、王様にご挨拶を。","ENG":"Luna, come over here and pay your respects to our lord.","TWN":"露娜，向王行禮。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"네? 네?","JPN":"え？　はい？","ENG":"Huh? What?","TWN":"啊？什麼？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"아, 아아, 안녕하세요…….","JPN":"こ、ここ、こんにちは……","ENG":"Oh... I-it's an honor to meet you...","TWN":"啊，啊啊，你好……"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"레지나란 분과 각별한 관계인 단원이랍니다.","JPN":"レジーナという方と格別な関係にある団員です。","ENG":"She is especially close with Regina.","TWN":"這個團員和那位蕾佳娜有著特別的關係。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"그 분을 위한 의식이니, 왕께서 흡족해하실 만큼 정성을 들이리라 장담드리겠습니다.","JPN":"その方のための儀式ですので、王様にご満足いただけるよう誠心誠意努力するでしょう。","ENG":"I assure you that because it is a ritual for Regina, Luna will go out of her way to please you, my lord.","TWN":"這是為那位準備的儀式，所以我保證她會傾注全部心血，讓王滿意。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"지휘자님? 저, 제가요? 혼자서?","JPN":"マエストロ？　あ、アタシがですか？　一人で？","ENG":"Chief Conductor? M-me? A-alone?","TWN":"指揮家？我…我嗎？一個人嗎？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"네퀴티아.","JPN":"ネキティア。","ENG":"Nequitia.","TWN":"莉奎蒂亞。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"말씀하시지요. 왕이시여.","JPN":"はい、王様。","ENG":"Yes, my lord.","TWN":"我的王請說。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"당신은 이제껏 교활하게 숨어 다니면서 연명해 왔죠.","JPN":"あなたは今まで狡猾に隠れながら生き延びてきました。","ENG":"You've made it this far by sneaking and hiding.","TWN":"你一直都在狡猾地東躲西藏、苟延殘喘。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"하지만 그건 어디까지나 냉정을 유지할 수 있을 때 가능한 방식이랍니다.","JPN":"ですが、それはあくまでも冷静を保つことができる時に可能なことです。","ENG":"However, this is only possible if one can maintain a level head.","TWN":"但那個方式只有在你保持冷酷無情才能實現。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"속내가 들켰어요. 저들 때문에 의식이 틀어지면 저희와 적대하게 될지도 모르기 때문이죠?","JPN":"あなたの考えはお見通しですよ。彼らのせいで儀式が失敗すれば、我々と敵対することになるかもしれないからでしょう？","ENG":"It appears you've lost your temper. You are doing this because you fear that if the ritual fails, we will become hostile towards you, correct?","TWN":"你暴露了內心的想法。如果因為她們的導致儀式出了差錯，說不定你就會和我們成為敵對關係，對吧？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"물론 깊이 엮이고 싶지 않으신 심정도 이해해요.","JPN":"もちろん、深く関わりたくないという気持ちはわかります。","ENG":"Of course, I understand you don't want to be deeply involved in this.","TWN":"當然，我們也理解你不想跟我們牽扯太深的心情。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"마왕 중에는 <color=#ffd34c>심연</color>을 언짢게 여기는 분들도 계시니까요.","JPN":"魔王の中には、<color=#ffd34c>深淵</color>を不快に思っている方々もいらっしゃいますから。","ENG":"Even some Demon Lords find the <color=#ffd34c>abyss</color> abhorrent.","TWN":"因為魔王中，也有不喜歡<color=#ffd34c>深淵</color>的人。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"저희는 미약하기 그지없기에, 주어진 망집을 이루기 위해서라면 어떤 치욕도 감수할 수 있답니다.","JPN":"私たちはこの上なく弱いので、与えられた妄執を叶えるためならどのような恥辱も耐えられるのです。","ENG":"We are frail creatures. So, in order to achieve this delusion, we will endure any shame.","TWN":"我們非常渺小，所以為了實現被賦予的妄執，可以承受任何恥辱。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"여러분과는…. 바라보는 경치가 다르지요.","JPN":"皆さんとは……見ている景色が違います。","ENG":"What we see beyond... is different from what you will see.","TWN":"和各位……看到的景色是不一樣的。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"후훗. 가슴에 가시를 품고도 언변은 여전히 유창하시네요.","JPN":"ふふっ。胸にトゲが刺さっていても、相変わらず弁が立ちますね。","ENG":"Ha ha. You still speak with a silver tongue, even with that thorn inside of you.","TWN":"呵呵，胸中有刺，口齒卻依然伶俐呢。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"그 가시, 계속 품고 다닐 작정이 아니라면 하루 빨리 빼내는 편을 추천드릴게요.","JPN":"そのトゲ、ずっとそのままにする気がないのなら、一日も早く抜くことをおすすめします。","ENG":"That thorn... We suggest you pull it out if you do not intend to keep it.","TWN":"那根刺，如果不想一直帶著，那我們建議你早點拔掉。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"당신이 원하는 것은 마련해 두었답니다.","JPN":"あなたのほしいものは用意しておきました。","ENG":"We already have prepared what you want.","TWN":"你想要的東西都準備好了。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"……사려 깊은 조언에 감사드립니다. 왕이시여.","JPN":"……ご配慮、感謝いたします。王様。","ENG":"...Thank you for your wise counsel, my lord.","TWN":"……謝謝王深謀遠慮的建議。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"루나라고 하셨죠? 흥겨운 연주 부탁드릴게요.","JPN":"ルナでしたか？　楽しい演奏をお願いしますね。","ENG":"Luna, was it? Please give us an exciting performance.","TWN":"你叫露娜是吧？請演奏得輕快些。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"아, 네! 죽은 사람도 벌떡 일어날 만큼 흥겹게 연주할게요!","JPN":"あ、はい！　死んだ人も起き上がるくらい楽しく演奏します！","ENG":"Oh, yes! I'll play so well that even the dead will come back and dance!","TWN":"啊，是！我會輕快地演奏，輕快到死人聽了也會跳起來！"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_LAUGH"}}}},{"id":"L42_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"자, 그러면 이제 레지나 님만 오시면 되려나……","JPN":"さて、あとはレジーナ様さえお越しになれば……","ENG":"Now, then... The only remaining piece is Miss Regina...","TWN":"那麼，那現在只要耐心等待蕾佳娜就行了……"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_LAUGH"}}}},{"id":"L43_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"선물을 받고 기뻐하셔야 할 텐데.","JPN":"プレゼントを見て喜んでくださるといいけれど。","ENG":"We wish she would be happy receiving our gift...","TWN":"收到禮物，她應該會高興才對。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_LAUGH"}}}}]`);export{e as default};